import React, { useState, useRef, ChangeEvent } from "react";
import FlexContainer from "../widget/FlexContainer";
import Scaffold from "../widget/Scaffold";
import Editor, { Monaco, OnMount } from '@monaco-editor/react'
import * as monaco from 'monaco-editor';
import { ResponsiveText } from "../widget/TextWidgets";
import { AiFillCopy } from "react-icons/ai";
import { AiOutlineBlock } from "react-icons/ai";
import { AwesomeButton, AwesomeButtonProgress } from "react-awesome-button";
import 'react-awesome-button/dist/styles.css';


export const Analysis = (): JSX.Element => {
    const editor1Ref = useRef<monaco.editor.IStandaloneCodeEditor | null>(null);
    const [message, setMessage] = useState('');
    const [imageSrc, setImageSrc] = useState('');
    const [inputValue, setInputValue] = useState('');

    const handleEditor1DidMount: OnMount = (editor, monaco) => {
        editor1Ref.current = editor;
    };

    const getEditor1Value = () => {
        if (editor1Ref.current) {
            return editor1Ref.current.getValue();
        }
    };

    const handleSecondEditor = (monaco: Monaco) => {
        monaco.editor.defineTheme('myCustomTheme', {
            base: 'vs-dark',
            inherit: true,
            rules: [],
            colors: {
              'editor.background': '#1E1E1E',
            }
        });
    };

    const handleInputChange = (event: ChangeEvent<HTMLInputElement>) => {
        setInputValue(event.target.value);
    };

    const requestAnalysis = async() => {
        const response = await fetch('http://168.188.125.50:20017/analysis', {
            method: 'POST',
            headers: {
                'Content-Type' : 'application/json',
            },
            body: JSON.stringify({code: getEditor1Value(), boj_problem_number: Number(inputValue)}),
        });

        if (!response.ok && response) {
            const data = await response.json();
            setMessage(data.message);
            return;
        }

        const data = await response.json();
        setMessage("Similarity with Average of others code: \n" + String(Math.round(Number(data.message) * 100) / 100));

        await requestPlot();
    };

    const requestPlot = async() => {
        const response = await fetch('http://168.188.125.50:20017/plot', {
            method: 'GET'
        });
        const blob = await response.blob();
        const url = URL.createObjectURL(blob);
        setImageSrc(url);
    };

    return <Scaffold>
        <FlexContainer flexDirection="column" height="100%" {...{ background: "#1e1e1e" }}>
            <FlexContainer height="10%" {...{ background: "#171717" }}>
                <FlexContainer width="100%" flexDirection="column">
                    <FlexContainer width="100%">
                        <FlexContainer width="100%" alignItems="center" justifyContent="space-between">
                            <FlexContainer alignItems="center">
                                <AiFillCopy color="white" size={20} style={{ marginLeft: 10 }} />
                                <ResponsiveText fontSize="Small" color="white" fontWeight={350} {...{ margin: 10 }}>Code analysis</ResponsiveText>
                            </FlexContainer>
                            <AwesomeButton type="primary" style={{ height: 30, marginRight: 10 }}>Learn more</AwesomeButton>
                        </FlexContainer>
                    </FlexContainer>
                    <FlexContainer width="100%">
                        <FlexContainer width="50%" alignItems="center">
                            <AiOutlineBlock color="white" style={{ marginLeft: 10 }} />
                            <ResponsiveText fontSize="Tiny" color="white" fontWeight={300} {...{ margin: 5 }}>Code</ResponsiveText>
                        </FlexContainer>
                        <FlexContainer width="50%" alignItems="center">
                            <AiOutlineBlock color="white" style={{ marginLeft: 10 }} />
                            <ResponsiveText fontSize="Tiny" color="white" fontWeight={300} {...{ margin: 5 }}>result</ResponsiveText>
                        </FlexContainer>
                    </FlexContainer>
                </FlexContainer> 
            </FlexContainer>
            <FlexContainer height="85%" justifyContent="flex-start" alignItems="center">
                <Editor height="100%" width="50%" theme="myCustomTheme" defaultLanguage="c" options={{ fontSize: 15 }} beforeMount={handleSecondEditor} onMount={handleEditor1DidMount} />
                <FlexContainer height="100%" width="50%" flexDirection="column">
                        {imageSrc ? (
                            <ResponsiveText fontSize="Small" color={"white"} fontWeight={300}>{message}</ResponsiveText>
                        ) : <ResponsiveText fontSize="Tiny" color={"white"} fontWeight={300}>No result yet ...</ResponsiveText>
                        }
                        <FlexContainer height="100%" width="100%" justifyContent="center">
                            {imageSrc ? <img src={imageSrc} alt="Fetched from server" style={{ width: "90%", height: "50%" }} /> : ''}
                        </FlexContainer>
                </FlexContainer>
            </FlexContainer>
            <FlexContainer justifyContent="flex-end" alignItems="center" height="5%" {...{ background: "#171717", paddingRight: 10 }}>
                <ResponsiveText fontSize="Tiny" color={"white"} fontWeight={300} {...{ marginRight: 10 }}>BOJ problem</ResponsiveText>
                <input type="text" onChange={handleInputChange} style={{ background: "#2f2f2f", border: "0px", color: "white", height: 20, marginRight: 10 }}></input>
                <AwesomeButtonProgress onPress={async (event, release) => {
                    await requestAnalysis();
                    release();
                }} type="primary" style={{ height: 30 }}>Analysis</AwesomeButtonProgress>
            </FlexContainer>
        </FlexContainer>
    </Scaffold>;
};
